#define GP_WB_GET_AK_STANDBY_RESET_RTUC_FROM_RESET_0(tmp) \
        ((tmp) & 0x01)

#define GP_WB_WRITE_AK_STANDBY_RESET_RTUC(val) do { \
          GP_WB_RANGE_CHECK(val, 0x01); \
          UInt32 halprop_h_tmp = (AK_STANDBY_REGMAP->reset_0.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000001)) | ((((val)) << 0) & (0x00000001)); \
          AK_STANDBY_REGMAP->reset_0.reg32[0] = halprop_h_tmp; \
        } while (0)

#define GP_WB_SET_AK_STANDBY_RESET_RTUC_TO_RESET_0(tmp, val) do { \
          GP_WB_SIZE_CHECK_U16(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x7FFE; \
          (tmp) |= ((UInt16)(val)); \
        } while (0)

