/* enable overrule control of sx_locked */
#define GP_WB_READ_AK_TX_SX_LOCKED_OVERRULE_ENA() \
        ((UInt8)(AK_TX_REGMAP->unnamedpb_tx_0x0000.reg32[0]))

#define GP_WB_WRITE_AK_TX_SX_LOCKED_OVERRULE_ENA(val) do { \
          GP_WB_RANGE_CHECK(val, 0x01); \
          AK_TX_REGMAP->unnamedpb_tx_0x0000.reg32[0] = (val); \
        } while (0)


/* sx_locked, overrule value */
#define GP_WB_READ_AK_TX_SX_LOCKED_OVERRULE() \
        ((UInt8)(AK_TX_REGMAP->unnamedpb_tx_0x0004.reg32[0]))

#define GP_WB_WRITE_AK_TX_SX_LOCKED_OVERRULE(val) do { \
          GP_WB_RANGE_CHECK(val, 0x01); \
          AK_TX_REGMAP->unnamedpb_tx_0x0004.reg32[0] = (val); \
        } while (0)


/* sx_locked status */
#define GP_WB_READ_AK_TX_SX_LOCKED_STATUS() \
        ((UInt8)(AK_TX_REGMAP->unnamedpb_tx_0x0008.reg32[0]))


/* register access functions for AK_TX_BBPTX_CONFIG */
#define GP_WB_READ_AK_TX_BBPTX_CONFIG() \
        ((UInt8)AK_TX_REGMAP->bbptx_config.reg32[0])

#define GP_WB_WRITE_AK_TX_BBPTX_CONFIG(val) \
      AK_TX_REGMAP->bbptx_config.reg32[0] = (val)

/* enable invertion of MSK data */
#define GP_WB_READ_AK_TX_EN_INV_MSK() \
        ((UInt8)((AK_TX_REGMAP->bbptx_config.reg32[0]) & 0x01))

#define GP_WB_GET_AK_TX_EN_INV_MSK_FROM_BBPTX_CONFIG(tmp) \
        ((tmp) & 0x01)

#define GP_WB_WRITE_AK_TX_EN_INV_MSK(val) do { \
          GP_WB_RANGE_CHECK(val, 0x01); \
          UInt32 halprop_h_tmp = (AK_TX_REGMAP->bbptx_config.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000001)) | ((((val)) << 0) & (0x00000001)); \
          AK_TX_REGMAP->bbptx_config.reg32[0] = halprop_h_tmp; \
        } while (0)

#define GP_WB_SET_AK_TX_EN_INV_MSK_TO_BBPTX_CONFIG(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x1E; \
          (tmp) |= ((UInt8)(val)); \
        } while (0)

/* enable generation of continuous modulated carrier */
#define GP_WB_READ_AK_TX_EN_CONT_MOD() \
        ((UInt8)(((AK_TX_REGMAP->bbptx_config.reg32[0]) >> 1) & 0x01))

#define GP_WB_GET_AK_TX_EN_CONT_MOD_FROM_BBPTX_CONFIG(tmp) \
        (((tmp) >> 1) & 0x01)

#define GP_WB_WRITE_AK_TX_EN_CONT_MOD(val) do { \
          GP_WB_RANGE_CHECK(val, 0x01); \
          UInt32 halprop_h_tmp = (AK_TX_REGMAP->bbptx_config.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000002)) | ((((val) << 1) << 0) & (0x00000002)); \
          AK_TX_REGMAP->bbptx_config.reg32[0] = halprop_h_tmp; \
        } while (0)

#define GP_WB_SET_AK_TX_EN_CONT_MOD_TO_BBPTX_CONFIG(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
          (tmp) &= 0x1D; \
          (tmp) |= (((UInt8)(val)) << 1); \
        } while (0)

/* enable PA always on when in Tx mode */
