#define GP_WB_SET_AK_SX_MOD_INVERT_TO_DTC_MI_ADJUST(tmp, val) do { \
          GP_WB_SIZE_CHECK_U32(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
