#define GP_WB_WRITE_AK_DMAS_SCB_WORD_MODE_0(val) do { \
          GP_WB_RANGE_CHECK(val, 0x03); \
          UInt32 halprop_h_tmp = (AK_DMAS_SCB_REGMAP->conf_0.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000003)) | ((((val)) << 0) & (0x00000003)); \
