#define GP_WB_WRITE_AK_DMAS_DCB_CONF_0(val) \
      AK_DMAS_DCB_REGMAP->conf_0.reg32[0] = (val)

/* Minimum number of idle cycles between accesses to the same dma channel. Should be increased to reduce copy speed. */
#define GP_WB_READ_AK_DMAS_DCB_ACCESS_LATENCY_0() \
        ((UInt8)((AK_DMAS_DCB_REGMAP->conf_0.reg32[0]) & 0x0F))

