/* The dma copy will be triggered as long as this bit is set to 1 and the destination buffer is not full and there is data to be copied from the read buffer. */
#define GP_WB_READ_AK_DMAS_DCB_CPY_TRIGGER_0() \
        ((UInt8)(((AK_DMAS_DCB_REGMAP->conf_0.reg32[0]) >> 6) & 0x01))

#define GP_WB_GET_AK_DMAS_DCB_CPY_TRIGGER_0_FROM_CONF_0(tmp) \
        (((tmp) >> 6) & 0x01)

#define GP_WB_WRITE_AK_DMAS_DCB_CPY_TRIGGER_0(val) do { \
          GP_WB_RANGE_CHECK(val, 0x01); \
          UInt32 halprop_h_tmp = (AK_DMAS_DCB_REGMAP->conf_0.reg32[0]); \
          halprop_h_tmp = (halprop_h_tmp & ~(0x00000040)) | ((((val) << 6) << 0) & (0x00000040)); \
          AK_DMAS_DCB_REGMAP->conf_0.reg32[0] = halprop_h_tmp; \
        } while (0)

#define GP_WB_SET_AK_DMAS_DCB_CPY_TRIGGER_0_TO_CONF_0(tmp, val) do { \
          GP_WB_SIZE_CHECK_U8(tmp); \
          GP_WB_RANGE_CHECK(val, 0x01); \
