#define GP_WB_AK_DMAS_DCB_RESET_POINTERS_0() \
        AK_DMAS_DCB_REGMAP->unnamedpb_dmas_dcb_0x0020.reg32[0] = (0x00000001)


/* Indicates that either the source buffer is empty or the destination buffer is full. The DMA_DCB CH_0 will not do any copy while this condition remains. */
#define GP_WB_READ_AK_DMAS_DCB_UNMASKED_BUFFER_COMPLETE_0_INTERRUPT() \
